ce/publish_action_from_dockerfile","releasePath":"/kamlad/nextdr/releases/new?marketplace=true","showPublishActionBanner":false},"rawBlobUrl":"https://github.com/kamlad/nextdr/raw/refs/heads/release/v1.1.6/install/NDR-schema.sql","renderImageOrRaw":false,"shortPath":null,"symbolsEnabled":true,"tabSize":4,"topBannersInfo":{"overridingGlobalFundingFile":false,"globalPreferredFundingPath":null,"showInvalidCitationWarning":false,"citationHelpUrl":"https://docs.github.com/github/creating-cloning-and-archiving-repositories/creating-a-repository-on-github/about-citation-files","actionsOnboardingTip":null},"truncated":false,"viewable":true,"workflowRedirectUrl":null},"copilotInfo":null,"copilotAccessAllowed":true,"copilotSpacesEnabled":true,"modelsAccessAllowed":false,"modelsRepoIntegrationEnabled":false,"isMarketplaceEnabled":true},"codeViewBlobLayoutRoute.StyledBlob":{"rawLines":["--","-- NextDR Supabase Database Schema","-- NDR-SCHEMA-VERSION: 1.1.6","-- NDR-UPGRADE-FROM: 0.0.0","-- NDR-SCHEMA-TYPE: FULL","--","","SET statement_timeout = 0;","SET lock_timeout = 0;","SET idle_in_transaction_session_timeout = 0;","SET client_encoding = 'UTF8';","SET standard_conforming_strings = on;","SELECT pg_catalog.set_config('search_path', '', false);","SET check_function_bodies = false;","SET xmloption = content;","SET client_min_messages = warning;","SET row_security = off;","","--","-- Name: SCHEMA public; Type: COMMENT; Schema: -; Owner: -","--","","COMMENT ON SCHEMA public IS 'standard public schema';","","","--","-- Name: pricing_plan_interval; Type: TYPE; Schema: public; Owner: -","--","","CREATE TYPE public.pricing_plan_interval AS ENUM (","    'day',","    'week',","    'month',","    'year'",");","","","--","-- Name: pricing_type; Type: TYPE; Schema: public; Owner: -","--","","CREATE TYPE public.pricing_type AS ENUM (","    'one_time',","    'recurring'",");","","","--","-- Name: subscription_status; Type: TYPE; Schema: public; Owner: -","--","","CREATE TYPE public.subscription_status AS ENUM (","    'trialing',","    'active',","    'canceled',","    'incomplete',","    'incomplete_expired',","    'past_due',","    'unpaid'",");","","","--","-- Name: check_step_approval(uuid); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.check_step_approval(step_id uuid) RETURNS boolean","    LANGUAGE plpgsql SECURITY DEFINER","    AS $$","BEGIN","    RETURN EXISTS (","        SELECT 1 FROM recovery_steps_new","        WHERE id = step_id","        AND requires_approval = true","        AND (","            approval_metadata-\u003e\u003e'approval_status' IS NULL","            OR approval_metadata-\u003e\u003e'approval_status' = 'pending'","        )","    );","END;","$$;","","--","-- Name: create_user_license_on_profile_insert(); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.create_user_license_on_profile_insert() RETURNS trigger","    LANGUAGE plpgsql","    AS $$","BEGIN","  -- Insert a new license row with the same ID as the profile","  INSERT INTO public.user_license (id, license_key, \"isActive\")","  VALUES (NEW.id, NULL, FALSE);","","  RETURN NEW;","END;","$$;","","--","-- Name: ensure_user_profiles(); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.ensure_user_profiles() RETURNS void","    LANGUAGE plpgsql SECURITY DEFINER","    AS $$BEGIN","    INSERT INTO user_profiles (id, email, role)","    SELECT id, email, 'viewer'","    FROM auth.users u","    WHERE NOT EXISTS (","        SELECT 1 FROM user_profiles p WHERE p.id = u.id","    );","END;$$;","","","--","-- Name: handle_new_user(); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.handle_new_user() RETURNS trigger","    LANGUAGE plpgsql SECURITY DEFINER","    AS $$BEGIN","    -- Check if profile already exists","    IF NOT EXISTS (SELECT 1 FROM public.user_profiles WHERE id = NEW.id) THEN","        INSERT INTO public.user_profiles (id, email, role)","        VALUES (NEW.id, NEW.email, 'admin');","    END IF;","    RETURN NEW;","END;$$;","","","--","-- Name: handle_user_deletion(); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.handle_user_deletion() RETURNS trigger","    LANGUAGE plpgsql SECURITY DEFINER","    AS $$","BEGIN","    -- Log the deletion in an audit table if needed","    -- For now, we'll just let the CASCADE handle the user_profiles deletion","    RETURN OLD;","END;","$$;","","","--","-- Name: is_admin(uuid); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.is_admin(user_id uuid) RETURNS boolean","    LANGUAGE plpgsql SECURITY DEFINER","    AS $_$","BEGIN","  RETURN EXISTS (","    SELECT 1 FROM public.user_roles","    WHERE user_id = $1 AND role = 'admin'","  );","END;","$_$;","","","--","-- Name: log_license_action(); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.log_license_action() RETURNS trigger","    LANGUAGE plpgsql","    AS $$","begin","  insert into license_logs (license_id, action, metadata)","  values (","    new.id,","    case","      when new.status != old.status then 'status_change'","      when new.usage_count \u003e old.usage_count then 'usage'","      else 'update'","    end,","    jsonb_build_object(","      'old_status', old.status,","      'new_status', new.status,","      'old_usage_count', old.usage_count,","      'new_usage_count', new.usage_count","    )","  );","  return new;","end;","$$;","","","--","-- Name: log_user_action(text, uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.log_user_action(action text, entity_id uuid, details jsonb DEFAULT '{}'::jsonb) RETURNS uuid","    LANGUAGE plpgsql SECURITY DEFINER","    AS $$","DECLARE","    log_id UUID;","BEGIN","    INSERT INTO audit_logs (","        user_id,","        action,","        entity_type,","        entity_id,","        details","    )","    VALUES (","        auth.uid(),","        action,","        'user',","        entity_id,","        details","    )","    RETURNING id INTO log_id;","    ","    RETURN log_id;","END;","$$;","","","--","-- Name: log_user_profile_deletion(); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.log_user_profile_deletion() RETURNS trigger","    LANGUAGE plpgsql SECURITY DEFINER","    AS $$","BEGIN","    PERFORM public.log_user_action(","        'user_deleted',","        OLD.id,","        jsonb_build_object(","            'email', OLD.email,","            'role', OLD.role,","            'status', OLD.status","        )","    );","    RETURN OLD;","END;","$$;","","","--","-- Name: log_user_profile_update(); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.log_user_profile_update() RETURNS trigger","    LANGUAGE plpgsql SECURITY DEFINER","    AS $$","BEGIN","    IF OLD.role != NEW.role THEN","        PERFORM public.log_user_action(","            'role_update',","            NEW.id,","            jsonb_build_object(","                'old_role', OLD.role,","                'new_role', NEW.role","            )","        );","    END IF;","","    IF OLD.status != NEW.status THEN","        PERFORM public.log_user_action(","            'status_update',","            NEW.id,","            jsonb_build_object(","                'old_status', OLD.status,","                'new_status', NEW.status","            )","        );","    END IF;","","    RETURN NEW;","END;","$$;","","","--","-- Name: resolve_step_assignees(uuid); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.resolve_step_assignees(step_id uuid) RETURNS TABLE(user_id uuid, email text, role text, status text)","    LANGUAGE plpgsql SECURITY DEFINER","    AS $$","BEGIN","    RETURN QUERY","    WITH step_info AS (","        SELECT assignee_type, assignee_id","        FROM recovery_steps_new","        WHERE id = step_id","    )","    SELECT ","        u.id as user_id,","        u.email,","        p.role,","        p.status","    FROM step_info s","    LEFT JOIN LATERAL (","        SELECT id, email, role, status","        FROM user_profiles","        WHERE s.assignee_type = 'user' AND id = s.assignee_id","        UNION ALL","        SELECT up.id, up.email, up.role, up.status","        FROM group_members gm","        JOIN user_profiles up ON up.id = gm.user_id","        WHERE s.assignee_type = 'group' AND gm.group_id = s.assignee_id","    ) u ON true;","END;","$$;","","","--","-- Name: update_customer_profile_timestamp(); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.update_customer_profile_timestamp() RETURNS trigger","    LANGUAGE plpgsql","    AS $$","begin","  new.updated_at = timezone('utc'::text, now());","  return new;","end;","$$;","","","--","-- Name: update_modified_column(); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.update_modified_column() RETURNS trigger","    LANGUAGE plpgsql","    AS $$","BEGIN","    NEW.updated_at = NOW();","    RETURN NEW;","END;","$$;","","","--","-- Name: update_updated_at_column(); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.update_updated_at_column() RETURNS trigger","    LANGUAGE plpgsql","    AS $$","BEGIN","    NEW.updated_at = NOW();","    RETURN NEW;","END;","$$;","","","--","-- Name: update_user_role(uuid, text); Type: FUNCTION; Schema: public; Owner: -","--","","CREATE FUNCTION public.update_user_role(user_id uuid, new_role text) RETURNS void","    LANGUAGE plpgsql SECURITY DEFINER","    AS $$","BEGIN","    -- Check if the current user is an admin","    IF NOT EXISTS (","        SELECT 1 FROM user_profiles","        WHERE id = auth.uid() AND role = 'admin'","    ) THEN","        RAISE EXCEPTION 'Only admins can update user roles';","    END IF;","","    -- Update the user's role","    UPDATE user_profiles","    SET role = new_role,","        updated_at = NOW()","    WHERE id = user_id;","","    -- Update the user's custom claims","    UPDATE auth.users","    SET raw_user_meta_data = jsonb_set(","        COALESCE(raw_user_meta_data, '{}'::jsonb),","        '{role}',","        to_jsonb(new_role)","    )","    WHERE id = user_id;","END;","$$;","","SET default_tablespace = '';","","SET default_table_access_method = heap;","","--","-- Name: activity_logs; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.activity_logs (","    id uuid DEFAULT gen_random_uuid() NOT NULL,","    user_id uuid,","    action text NOT NULL,","    entity_type text NOT NULL,","    entity_id text,","    metadata jsonb DEFAULT '{}'::jsonb,","    created_at timestamp with time zone DEFAULT now()",");","","","--","-- Name: agent_commands; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.agent_commands (","    id bigint NOT NULL,","    created_at timestamp with time zone DEFAULT now() NOT NULL,","    command text",");","","","--","-- Name: COLUMN agent_commands.command; Type: COMMENT; Schema: public; Owner: -","--","","COMMENT ON COLUMN public.agent_commands.command IS 'agent command';","","","--","-- Name: agent_commands_id_seq; Type: SEQUENCE; Schema: public; Owner: -","--","","ALTER TABLE public.agent_commands ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY (","    SEQUENCE NAME public.agent_commands_id_seq","    START WITH 1","    INCREMENT BY 1","    NO MINVALUE","    NO MAXVALUE","    CACHE 1",");","","","--","-- Name: agent_response; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.agent_response (","    id bigint NOT NULL,","    created_at timestamp with time zone DEFAULT now() NOT NULL,","    response text,","    command_id bigint",");","","","--","-- Name: COLUMN agent_response.command_id; Type: COMMENT; Schema: public; Owner: -","--","","COMMENT ON COLUMN public.agent_response.command_id IS 'id from source command from agent_commands table';","","","--","-- Name: agent_response_id_seq; Type: SEQUENCE; Schema: public; Owner: -","--","","ALTER TABLE public.agent_response ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY (","    SEQUENCE NAME public.agent_response_id_seq","    START WITH 1","    INCREMENT BY 1","    NO MINVALUE","    NO MAXVALUE","    CACHE 1",");","","","--","-- Name: application_groups; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.application_groups (","    id bigint NOT NULL,","    name character varying(255) NOT NULL,","    description text,","    vm_ids text[],","    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,","    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,","    project_id text,","    resources jsonb DEFAULT '\"\"'::jsonb NOT NULL,","    data_center_id bigint,","    target_datacenter_id bigint,","    target_bucket text,","    backup_region text,","    backup_zone text,","    minimum_backup_count integer DEFAULT 0",");","","","--","-- Name: TABLE application_groups; Type: COMMENT; Schema: public; Owner: -","--","","COMMENT ON TABLE public.application_groups IS 'This is a duplicate of applications';","","","--","-- Name: application_groups_id_seq; Type: SEQUENCE; Schema: public; Owner: -","--","","ALTER TABLE public.application_groups ALTER COLUMN id ADD GENERATED ALWAYS AS IDENTITY (","    SEQUENCE NAME public.application_groups_id_seq","    START WITH 1","    INCREMENT BY 1","    NO MINVALUE","    NO MAXVALUE","    CACHE 1",");","","","--","-- Name: applications; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.applications (","    id bigint NOT NULL,","    name character varying(255) NOT NULL,","    description text,","    vm_ids text[],","    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,","    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,","    backupcatalog bigint",");","","","--","-- Name: COLUMN applications.backupcatalog; Type: COMMENT; Schema: public; Owner: -","--","","COMMENT ON COLUMN public.applications.backupcatalog IS 'link to backup catalog';","","","--","-- Name: applications_id_seq; Type: SEQUENCE; Schema: public; Owner: -","--","","ALTER TABLE public.applications ALTER COLUMN id ADD GENERATED ALWAYS AS IDENTITY (","    SEQUENCE NAME public.applications_id_seq","    START WITH 1","    INCREMENT BY 1","    NO MINVALUE","    NO MAXVALUE","    CACHE 1",");","","","--","-- Name: approval_tokens; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.approval_tokens (","    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,","    step_id uuid NOT NULL,","    approver_id uuid NOT NULL,","    token text NOT NULL,","    expires_at timestamp with time zone NOT NULL,","    created_at timestamp with time zone DEFAULT now(),","    is_used boolean DEFAULT false,","    used_at timestamp with time zone,","    used_by uuid,","    is_checkpoint boolean DEFAULT false,","    checkpoint_id uuid",");","","","--","-- Name: audit_logs; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.audit_logs (","    id uuid DEFAULT gen_random_uuid() NOT NULL,","    user_id uuid,","    action text NOT NULL,","    entity_type text NOT NULL,","    entity_id uuid,","    details jsonb DEFAULT '{}'::jsonb,","    created_at timestamp with time zone DEFAULT now() NOT NULL",");","","","--","-- Name: backup_execution; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.backup_execution (","    execution_id text NOT NULL,","    created_at timestamp with time zone DEFAULT now() NOT NULL,","    schedule_id text DEFAULT ''::text NOT NULL,","    project_config_snapshot jsonb NOT NULL,","    vm_snapshots jsonb,","    status text DEFAULT ''::text NOT NULL",");","","","--","-- Name: backup_run; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.backup_run (","    id uuid DEFAULT gen_random_uuid() NOT NULL,","    started_at timestamp with time zone DEFAULT now() NOT NULL,","    completed_at timestamp with time zone,","    application_group_id bigint NOT NULL,","    status text DEFAULT 'not null check (status in (''pending'',''completed'',''failed'')),'::text,","    summary jsonb,","    created_at timestamp with time zone DEFAULT now(),","    project_config jsonb DEFAULT '{}'::jsonb NOT NULL,","    retention_period bigint DEFAULT '7'::bigint,","    datacentre_config jsonb not null default '\"\"'::jsonb",");","","","--","-- Name: backupcatalogs; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.backupcatalogs (","    id bigint NOT NULL,","    created_at timestamp with time zone DEFAULT now() NOT NULL,","    hostname text,","    username text,","    password text,","    port text,","    apitoken text,","    hypervisor_type text,","    user_id uuid DEFAULT auth.uid()",");","","","--","-- Name: TABLE backupcatalogs; Type: COMMENT; Schema: public; Owner: -","--","","COMMENT ON TABLE public.backupcatalogs IS 'Table for backup catalogs like Cohesity, CommVault, Rubrik';","","","--","-- Name: backupcatalogs_id_seq; Type: SEQUENCE; Schema: public; Owner: -","--","","ALTER TABLE public.backupcatalogs ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY (","    SEQUENCE NAME public.backupcatalogs_id_seq","    START WITH 1","    INCREMENT BY 1","    NO MINVALUE","    NO MAXVALUE","    CACHE 1",");","","","--","-- Name: customers; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.customers (","    id uuid NOT NULL,","    stripe_customer_id text",");","","","--","-- Name: datacenters; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.datacenters (","    id bigint NOT NULL,","    created_at timestamp with time zone DEFAULT now() NOT NULL,","    hostname text,","    username text,","    password text,","    port text,","    apitoken text,","    hypervisor_type text",");","","","--","-- Name: datacenters2; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.datacenters2 (","    id bigint NOT NULL,","    created_at timestamp with time zone DEFAULT now() NOT NULL,","    hypervisor_type text,","    apitoken json,","    project_id text,","    name text DEFAULT ''::text NOT NULL,","    is_control_plane boolean null default false",");","","","--","-- Name: COLUMN datacenters2.name; Type: COMMENT; Schema: public; Owner: -","--","","COMMENT ON COLUMN public.datacenters2.name IS 'Name of the datacentre';","","","--","-- Name: datacenters2_id_seq; Type: SEQUENCE; Schema: public; Owner: -","--","","ALTER TABLE public.datacenters2 ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY (","    SEQUENCE NAME public.datacenters2_id_seq","    START WITH 1","    INCREMENT BY 1","    NO MINVALUE","    NO MAXVALUE","    CACHE 1",");","","","--","-- Name: datacenters_id_seq; Type: SEQUENCE; Schema: public; Owner: -","--","","ALTER TABLE public.datacenters ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY (","    SEQUENCE NAME public.datacenters_id_seq","    START WITH 1","    INCREMENT BY 1","    NO MINVALUE","    NO MAXVALUE","    CACHE 1",");","","","--","-- Name: disks; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.disks (","    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,","    vm_id bigint,","    name character varying(255) NOT NULL,","    type character varying(50) NOT NULL,","    size_gb integer NOT NULL,","    recovery_points jsonb DEFAULT '[]'::jsonb,","    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,","    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,","    CONSTRAINT disks_type_check CHECK (((type)::text = ANY (ARRAY[('os'::character varying)::text, ('data'::character varying)::text])))",");","","","--","-- Name: group_members; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.group_members (","    id uuid DEFAULT gen_random_uuid() NOT NULL,","    group_id uuid NOT NULL,","    user_id uuid NOT NULL,","    role text DEFAULT 'member'::text NOT NULL,","    created_at timestamp with time zone DEFAULT now() NOT NULL,","    updated_at timestamp with time zone DEFAULT now() NOT NULL,","    created_by uuid,","    CONSTRAINT group_members_role_check CHECK ((role = ANY (ARRAY['admin'::text, 'member'::text])))",");","","","--","-- Name: integration_configs; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.integration_configs (","    id uuid DEFAULT gen_random_uuid() NOT NULL,","    source text NOT NULL,","    enabled boolean DEFAULT false NOT NULL,","    last_sync_at timestamp with time zone,","    sync_status text,","    error_message text,","    config jsonb DEFAULT '{}'::jsonb NOT NULL,","    created_at timestamp with time zone DEFAULT now() NOT NULL,","    updated_at timestamp with time zone DEFAULT now() NOT NULL,","    CONSTRAINT integration_configs_source_check CHECK ((source = ANY (ARRAY['native'::text, 'gcp_ad'::text]))),","    CONSTRAINT integration_configs_sync_status_check CHECK ((sync_status = ANY (ARRAY['idle'::text, 'syncing'::text, 'success'::text, 'error'::text, 'in_progress'::text])))",");","","","--","-- Name: internal_groups; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.internal_groups (","    id uuid DEFAULT gen_random_uuid() NOT NULL,","    name text NOT NULL,","    description text,","    type text DEFAULT 'internal'::text NOT NULL,","    created_at timestamp with time zone DEFAULT now() NOT NULL,","    updated_at timestamp with time zone DEFAULT now() NOT NULL,","    created_by uuid,","    metadata jsonb DEFAULT '{}'::jsonb,","    CONSTRAINT internal_groups_type_check CHECK ((type = 'internal'::text))",");","","","--","-- Name: license_logs; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.license_logs (","    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,","    license_id uuid,","    action text,","    \"timestamp\" timestamp with time zone DEFAULT timezone('utc'::text, now()),","    metadata jsonb",");","","","--","-- Name: licenses_backup; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.licenses_backup (","    id uuid DEFAULT gen_random_uuid() NOT NULL,","    customer_id text NOT NULL,","    jwt text NOT NULL,","    issued_at timestamp with time zone DEFAULT now()",");","","","--","-- Name: organizations; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.organizations (","    id uuid DEFAULT gen_random_uuid() NOT NULL,","    name text NOT NULL,","    domain text,","    created_at timestamp with time zone DEFAULT now(),","    status text DEFAULT 'active'::text NOT NULL,","    settings jsonb DEFAULT '{}'::jsonb",");","","","--","-- Name: prices; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.prices (","    id text NOT NULL,","    product_id text,","    active boolean,","    description text,","    unit_amount bigint,","    currency text,","    type public.pricing_type,","    \"interval\" public.pricing_plan_interval,","    interval_count integer,","    trial_period_days integer,","    metadata jsonb,","    CONSTRAINT prices_currency_check CHECK ((char_length(currency) = 3))",");","","","--","-- Name: products; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.products (","    id text NOT NULL,","    active boolean,","    name text,","    description text,","    image text,","    metadata jsonb",");","","","--","-- Name: recovery_plan_audit_log; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.recovery_plan_audit_log (","    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,","    recovery_plan_id uuid NOT NULL,","    step_id uuid NOT NULL,","    action text NOT NULL,","    performed_by uuid NOT NULL,","    details jsonb,","    ip_address text,","    created_at timestamp with time zone DEFAULT now()",");","","","--","-- Name: recovery_plan_checkpoints; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.recovery_plan_checkpoints (","    id uuid DEFAULT gen_random_uuid() NOT NULL,","    recovery_plan_id uuid NOT NULL,","    step_id uuid NOT NULL,","    approver_id uuid,","    approver_role text,","    approval_required boolean DEFAULT true NOT NULL,","    approval_status text,","    approved_at timestamp with time zone,","    approved_by uuid,","    approval_metadata jsonb DEFAULT '{}'::jsonb,","    created_at timestamp with time zone DEFAULT now() NOT NULL,","    updated_at timestamp with time zone DEFAULT now() NOT NULL,","    CONSTRAINT recovery_plan_checkpoints_approval_status_check CHECK ((approval_status = ANY (ARRAY['pending'::text, 'approved'::text, 'rejected'::text]))),","    CONSTRAINT recovery_plan_checkpoints_check CHECK ((((approver_id IS NOT NULL) AND (approver_role IS NULL)) OR ((approver_id IS NULL) AND (approver_role IS NOT NULL))))",");","","","--","-- Name: recovery_plan_execution; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.recovery_plan_execution (","    id bigint NOT NULL,","    created_at timestamp with time zone DEFAULT (now() AT TIME ZONE 'utc'::text) NOT NULL,","    completed_at timestamp without time zone DEFAULT (now() AT TIME ZONE 'utc'::text),","    status text DEFAULT ''::text,","    recovery_plan_id uuid DEFAULT gen_random_uuid(),","    completed_steps bigint,","    failed_steps bigint,","    error_message text,","    metadata jsonb",");","","","--","-- Name: recovery_plan_execution_id_seq; Type: SEQUENCE; Schema: public; Owner: -","--","","ALTER TABLE public.recovery_plan_execution ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY (","    SEQUENCE NAME public.recovery_plan_execution_id_seq","    START WITH 1","    INCREMENT BY 1","    NO MINVALUE","    NO MAXVALUE","    CACHE 1",");","","","--","-- Name: recovery_plan_progress; Type: TABLE; Schema: public; Owner: -","--","","CREATE TABLE public.recovery_plan_progress (","    id uuid DEFAULT gen_random_uuid() NOT NULL,","    recovery_plan_id uuid NOT NULL,","    step_id uuid NOT NULL,","    status text NOT NULL,","    started_at timestamp with time zone,","    completed_at timestamp with time zone,","    execution_metadata jsonb DEFAULT '{}'::jsonb,","    created_at timestamp with time zone DEFAULT now() NOT NULL,","    updated_at timest