S public.recovery_run_reports (","    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),","    run_id TEXT NOT NULL UNIQUE,","    report_json JSONB NOT NULL,","    report_hash TEXT NOT NULL,","    pdf_path TEXT NOT NULL,","    report_version TEXT NOT NULL,","    schema_version TEXT NOT NULL,","    generated_at TIMESTAMPTZ NOT NULL,","    immutable BOOLEAN NOT NULL DEFAULT true,","    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()",");","","CREATE INDEX IF NOT EXISTS idx_recovery_run_reports_run_id ON public.recovery_run_reports(run_id);","CREATE INDEX IF NOT EXISTS idx_recovery_run_reports_generated_at ON public.recovery_run_reports(generated_at DESC);","","-- RLS: allow service role full access; optional read for authenticated users","ALTER TABLE public.recovery_run_reports ENABLE ROW LEVEL SECURITY;","","CREATE POLICY \"Service role full access on recovery_run_reports\"","    ON public.recovery_run_reports","    FOR ALL","    USING (true)","    WITH CHECK (true);","","","-- Execution run reports: immutable report snapshots per execution run","CREATE TABLE IF NOT EXISTS public.execution_run_reports (","    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),","    run_id TEXT NOT NULL UNIQUE,","    report_json JSONB NOT NULL,","    report_hash TEXT NOT NULL,","    pdf_path TEXT NOT NULL,","    report_version TEXT NOT NULL DEFAULT '1.0.0',","    schema_version TEXT NOT NULL DEFAULT '1.0.0',","    generated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),","    immutable BOOLEAN NOT NULL DEFAULT true",");","","CREATE INDEX IF NOT EXISTS idx_execution_run_reports_run_id ON public.execution_run_reports(run_id);","CREATE INDEX IF NOT EXISTS idx_execution_run_reports_generated_at ON public.execution_run_reports(generated_at DESC);","","ALTER TABLE public.execution_run_reports ENABLE ROW LEVEL SECURITY;","","CREATE POLICY \"Authenticated users can read execution_run_reports\"","    ON public.execution_run_reports","    FOR SELECT","    TO authenticated","    USING (auth.role() = 'authenticated'::text);","","CREATE POLICY \"Authenticated users can insert execution_run_reports\"","    ON public.execution_run_reports","    FOR INSERT","    TO authenticated","    WITH CHECK (auth.role() = 'authenticated'::text);","","CREATE POLICY \"Authenticated users can update execution_run_reports\"","    ON public.execution_run_reports","    FOR UPDATE","    TO authenticated","    USING (auth.role() = 'authenticated'::text)","    WITH CHECK (auth.role() = 'authenticated'::text);","","CREATE POLICY \"Authenticated users can delete execution_run_reports\"","    ON public.execution_run_reports","    FOR DELETE","    TO authenticated","    USING (auth.role() = 'authenticated'::text);","","","","create table public.audit_events (","  event_id uuid not null default gen_random_uuid (),","  timestamp_utc timestamp with time zone not null default now(),","  actor character varying null default 'system'::character varying,","  actor_type character varying null default 'system'::character varying, -- 'human' | 'system'","  action character varying null default ''::character varying,","  resource_type character varying null default ''::character varying,","  resource_id character varying null default ''::character varying,","  resource_version character varying null,","  severity character varying null default 'info'::character varying, -- 'info' | 'warn' | 'high'","  correlation_id character varying null,","  execution_id character varying null,","  incident_id character varying null,","  before jsonb null,","  after jsonb null,","  metadata jsonb null default '{}'::jsonb,","  constraint audit_events_pkey primary key (event_id)",");","","","-- Enable RLS","alter table public.audit_events enable row level security;","","-- Read: any authenticated user","create policy \"audit_events_read_authenticated\"","on public.audit_events","for select","to authenticated","using (true);","","-- Write: any authenticated user (insert)","create policy \"audit_events_insert_authenticated\"","on pu